              const b = block as ContentBlock & { geometry?: unknown; axis?: unknown }
              if (b.type === ('question_geometry' as string)) {
                return (
                  <div key={b.id}>
                    <GeometryRenderer blockId={b.id} spec={b.geometry as GeometrySpecV1} />
                  </div>
                )
