import { HelpSystem } from '../components/HelpSystem'
import { useHelpSystem } from '../hooks/useHelpSystem'
import {
  checkQuestionAnswer,
  getInitialAnswer,
  checkSvgAnswer,
  getInitialSvgAnswer,
  type AnswerErrorMessages,
} from '../utils/answerChecking'
